const API_BASE_URL = 'https://7fe9ef0a6473.ngrok-free.app/api';

export type ApiResponse<T> = {
    status: boolean;
    message: string;
    data: T;
};

// Define the structure of the login response
export type LoginResponse = {
    user: User;
    token: string;
};

// Keys for storing data
const AUTH_TOKEN_KEY = 'authToken';
const AUTH_USER_KEY = 'authUser';

// Storage Utility Functions (using localStorage as a stand-in for cookies/better storage)
export const saveAuthData = (token: string, user: User) => {
    localStorage.setItem(AUTH_TOKEN_KEY, token);
    localStorage.setItem(AUTH_USER_KEY, JSON.stringify(user));
};

export const getAuthToken = (): string | null => {
    return localStorage.getItem(AUTH_TOKEN_KEY);
};

export const getAuthUser = (): User | null => {
    const userJson = localStorage.getItem(AUTH_USER_KEY);
    return userJson ? JSON.parse(userJson) : null;
};

export const clearAuthData = () => {
    localStorage.removeItem(AUTH_TOKEN_KEY);
    localStorage.removeItem(AUTH_USER_KEY);
};

let authUserId: string | null = null;

export const setAuthUserId = (id: string) => {
    authUserId = id;
};

export const clearAuthUserId = () => {
    authUserId = null;
};

async function request<T>(
    endpoint: string,
    options: RequestInit = {},
): Promise<T> {
    const headers = new Headers(options.headers || {});
    headers.set('Content-Type', 'application/json');
    headers.set('Accept', 'application/json');

    const token = getAuthToken();
    if (token) {
        headers.set('Authorization', `Bearer ${token}`);
    }

    const response = await fetch(`${API_BASE_URL}${endpoint}`, {
        ...options,
        headers,
    });

    const json = await response.json() as ApiResponse<T>;

    if (!response.ok || !json.status) {
        throw new Error(json.message || 'An API error occurred');
    }

    return json.data;
}

// --- API Functions ---

export const login = async (email: string, password: string): Promise<User> => {
    console.log('API Client Login called');

    // Check for mock users first
    const mockUser = MOCK_USERS.find(u => u.email === email);
    if (mockUser) {
        console.log('Mock Login Success', mockUser);
        saveAuthData('mock-token-' + mockUser.id, mockUser);
        return mockUser;
    }

    const loginResponse = await request<LoginResponse>('/login', {
        method: 'POST',
        body: JSON.stringify({ email, password }),
    });

    // 1. Save the token and user details upon successful login
    console.log(loginResponse.token, loginResponse.user);
    saveAuthData(loginResponse.token, loginResponse.user);

    // 2. Return the user object, as the original function signature suggests
    return loginResponse.user;
};

export const registerChurch = (
    churchName: string,
    adminName: string,
    adminEmail: string,
    adminPassword: string,
): Promise<User> => {
    if (adminEmail.includes('mock')) {
        const newUser = { id: 'user-' + Date.now(), name: adminName, email: adminEmail, role: Role.SUPER_ADMIN, church_id: 'church-1', section_id: null, department_id: null };
        saveAuthData('mock-token-' + newUser.id, newUser);
        return Promise.resolve(newUser);
    }
    return request<User>('/register', {
        method: 'POST',
        body: JSON.stringify({
            churchName,
            adminName,
            adminEmail,
            adminPassword,
        }),
    });
};

export const getRequisitions = (): Promise<Requisition[]> => {
    const user = getAuthUser();
    if (user?.id.startsWith('user-')) return Promise.resolve(MOCK_REQUISITIONS);
    return request<Requisition[]>(`/requisitions`);
};

export const getRequisitionById = (
    id: string,
): Promise<Requisition> => {
    const user = getAuthUser();
    if (user?.id.startsWith('user-')) {
        const req = MOCK_REQUISITIONS.find(r => r.id === id);
        if (req) return Promise.resolve(req);
    }
    return request<Requisition>(`/requisitions/${id}`);
};

export const createRequisition = (
    data: Omit<
        Requisition,
        | 'id'
        | 'status'
        | 'created_at'
        | 'updated_at'
        | 'activity_log'
        | 'approvals'
        | 'payment'
        | 'final_receipt'
        | 'requested_by'
        | 'department'
    >,
): Promise<Requisition> => {
    const user = getAuthUser();
    if (user?.id.startsWith('user-')) {
        const newReq: Requisition = {
            ...data,
            id: 'req-' + Date.now(),
            status: RequisitionStatus.PENDING,
            created_at: new Date().toISOString(),
            updated_at: new Date().toISOString(),
            requested_by: user,
            department: MOCK_CHURCH.sections[0].departments[0], // Default
            attachments: [],
            final_receipt: null,
            approvals: [],
            activity_log: []
        };
        return Promise.resolve(newReq);
    }
    return request<Requisition>('/requisitions', {
        method: 'POST',
        body: JSON.stringify(data),
    });
};

export const updateRequisition = (
    id: string,
    data: Partial<Requisition>,
): Promise<Requisition> => {
    const user = getAuthUser();
    if (user?.id.startsWith('user-')) {
        const req = MOCK_REQUISITIONS.find(r => r.id === id);
        if (req) return Promise.resolve({ ...req, ...data });
    }
    return request<Requisition>(`/requisitions/${id}`, {
        method: 'PUT',
        body: JSON.stringify(data),
    });
};

