export const processWorkflowAction = (
    reqId: string,
    action: 'APPROVE' | 'REJECT' | 'REQUEST_CHANGES',
    comments: string,
): Promise<Requisition> => {
    const user = getAuthUser();
    if (user?.id.startsWith('user-')) {
        const req = MOCK_REQUISITIONS.find(r => r.id === reqId);
        if (req) return Promise.resolve({ ...req, status: action === 'APPROVE' ? RequisitionStatus.APPROVED_BY_DEPT_HEAD : RequisitionStatus.REJECTED });
    }
    return request<Requisition>(`/requisitions/${reqId}/action`, {
        method: 'POST',
        body: JSON.stringify({ action, comments }),
    });
};

